// Настройки
// Используем '/' чтобы подключаться к тому же адресу, откуда открыт сайт (localhost)
const SERVER_URL = '/'; 
const SPEED = 5;

// Элементы экрана
const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');
const statusDiv = document.getElementById('status');
const coordsDiv = document.getElementById('coords');

// Настройка экрана
canvas.width = window.innerWidth;
canvas.height = window.innerHeight;
window.addEventListener('resize', () => {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
});

// ГЛОБАЛЬНЫЕ ДАННЫЕ (доступны во всех файлах)
window.game = {
    players: {},    // Тут живут все игроки
    myId: null,     // Мой ID
    socket: null    // Сокет
};

console.log("1. Глобальные настройки загружены.");

function drawGrid() {
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.1)';
    ctx.lineWidth = 1;
    const gridSize = 50;

    // Вертикальные линии
    for (let x = 0; x <= canvas.width; x += gridSize) {
        ctx.beginPath();
        ctx.moveTo(x, 0);
        ctx.lineTo(x, canvas.height);
        ctx.stroke();
    }

    // Горизонтальные линии
    for (let y = 0; y <= canvas.height; y += gridSize) {
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(canvas.width, y);
        ctx.stroke();
    }
}

function drawGame() {
    // 1. Чистим экран
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // 2. Рисуем сетку (чтобы не было скучно)
    drawGrid();

    // 3. Рисуем всех игроков из памяти (window.game.players)
    for (let id in window.game.players) {
        const p = window.game.players[id];
        const isMe = (id === window.game.myId);

        // Тень
        ctx.beginPath();
        ctx.arc(p.x, p.y + 15, 20, 0, Math.PI * 2);
        ctx.fillStyle = "rgba(0,0,0,0.3)";
        ctx.fill();

        // Тело
        ctx.beginPath();
        ctx.arc(p.x, p.y, 20, 0, Math.PI * 2);
        ctx.fillStyle = p.color || 'white';
        ctx.fill();

        // Обводка
        if (isMe) {
            ctx.lineWidth = 4;
            ctx.strokeStyle = "white";
            ctx.stroke();
            // Золотая корона
            ctx.fillStyle = "gold";
            ctx.font = "20px Arial";
            ctx.textAlign = "center";
            ctx.fillText("👑", p.x, p.y - 30);
        } else {
            ctx.lineWidth = 2;
            ctx.strokeStyle = "black";
            ctx.stroke();
        }
    }
}

console.log("3. Рендерер загружен.");

