function checkDependencies() {
    const errors = [];
    if (!window.game) errors.push("globals.js не загружен");
    if (typeof getNextPosition !== 'function') errors.push("controls.js не загружен");
    if (typeof drawGame !== 'function') errors.push("renderer.js не загружен");
