const SERVER_URL = 'https://rgp-game.onrender.com';
const SPEED = 5;

// Объявляем переменные, но инициализируем (ищем их в HTML) позже
let canvas, ctx, statusDiv, coordsDiv;

// ГЛОБАЛЬНЫЕ ДАННЫЕ
window.game = {
    players: {},
    myId: null,
    socket: null,
    isReady: false // Флаг, что все готово
};

// Функция инициализации DOM элементов
function initGlobals() {
    canvas = document.getElementById('gameCanvas');
    statusDiv = document.getElementById('status');
    coordsDiv = document.getElementById('coords');

    if (canvas) {
        ctx = canvas.getContext('2d');
        // Настройка размера экрана
        canvas.width = window.innerWidth;
        canvas.height = window.innerHeight;

        window.addEventListener('resize', () => {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
        });

        window.game.isReady = true;
        console.log("1. Globals: Canvas найден и настроен.");
    } else {
        console.error("CRITICAL: Canvas не найден!");
    }
}

// Запускаем поиск элементов сразу, так как скрипт в конце body
initGlobals();

console.log("3. Renderer: Загрузка...");

function drawGrid() {
    if (!ctx) return; // Защита

    ctx.strokeStyle = 'rgba(255, 255, 255, 0.1)';
    ctx.lineWidth = 1;
    const gridSize = 50;

    for (let x = 0; x <= canvas.width; x += gridSize) {
        ctx.beginPath();
        ctx.moveTo(x, 0);
        ctx.lineTo(x, canvas.height);
        ctx.stroke();
    }

    for (let y = 0; y <= canvas.height; y += gridSize) {
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(canvas.width, y);
        ctx.stroke();
    }
}

function drawGame() {
    // Если глобальные настройки еще не загрузились - выходим
    if (!window.game.isReady || !ctx) return;

    // 1. Чистим экран
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // 2. Рисуем сетку
    drawGrid();

    // 3. Рисуем игроков
    for (let id in window.game.players) {
        const p = window.game.players[id];
        const isMe = (id === window.game.myId);

        ctx.beginPath();
        ctx.arc(p.x, p.y + 15, 20, 0, Math.PI * 2);
        ctx.fillStyle = "rgba(0,0,0,0.3)";
        ctx.fill();

        ctx.beginPath();
        ctx.arc(p.x, p.y, 20, 0, Math.PI * 2);
        ctx.fillStyle = p.color || 'white';
        ctx.fill();

        if (isMe) {
            ctx.lineWidth = 4;
            ctx.strokeStyle = "white";
            ctx.stroke();
            ctx.fillStyle = "gold";
            ctx.font = "20px Arial";
            ctx.textAlign = "center";
            ctx.fillText("👑", p.x, p.y - 30);
        } else {
            ctx.lineWidth = 2;
            ctx.strokeStyle = "black";
            ctx.stroke();
        }
    }
}
